module sr_latch (
    input wire Inv_S,
    input wire R,
    output reg Q,
    output reg Q_not
);
    always @ (Inv_S or R) begin
        if (Inv_S && ~R) begin
            Q <= 1'b1;
            Q_not <= 1'b0;
        end else if (~Inv_S && R) begin
            Q <= 1'b0;
            Q_not <= 1'b1;
        end else if (~Inv_S && ~R) begin
            // retain previous state
            Q <= Q;
            Q_not <= Q_not;
        end
    end
endmodule
